  Promise<WsResponse<T>>;
getConversationRecvMessageOpt: (data: string[], operationID?: string) =>
  Promise<WsResponse<ConversationItem[]>>;
```

相关事件：

```ts
on<E extends CbEvents>(event: E, fn: Cbfn<E>): this;
off<E extends CbEvents>(event: E, fn: Cbfn<E>): this | undefined;
CbEvents.OnRecvNewMessages
CbEvents.OnTotalUnreadMessageCountChanged
```

响应和事件载荷使用以下通用结构：

```ts
type WsResponse<T> = {
  event: string;
  errCode: number;
  errMsg: string;
  data: T;
  operationID: string;
};
type WSEvent<T = unknown> = {
  event: CbEvents;
  data: T;
  errCode: number;
  errMsg: string;
  operationID: string;
