  Promise<WsResponse<ConversationItem[]>>;
getSpecifiedGroupsInfo: (params: string[], operationID?: string) =>
  Promise<WsResponse<GroupItem[]>>;
getGroupMemberList: (params: GetGroupMemberParams, operationID?: string) =>
  Promise<WsResponse<GroupMemberItem[]>>;
```

相关事件：

```ts
on<E extends CbEvents>(event: E, fn: Cbfn<E>): this;
off<E extends CbEvents>(event: E, fn: Cbfn<E>): this | undefined;
CbEvents.OnSyncServerFinish
CbEvents.OnConversationChanged
CbEvents.OnGroupInfoChanged
CbEvents.OnGroupMemberInfoChanged
```

响应和事件载荷使用以下通用结构：

```ts
type WsResponse<T> = {
  event: string;
  errCode: number;
  errMsg: string;
  data: T;
  operationID: string;
};
type WSEvent<T = unknown> = {
  event: CbEvents;
  data: T;
  errCode: number;
  errMsg: string;
  operationID: string;
};
```

